+
+    local procedure ConvertNonDeductibleVATAmountToJobCurrency(GenJnlLine: Record "Gen. Journal Line"): Decimal
+    var
+        NonDeductibleVATAmountLCY: Decimal;
+        NonDeductibleVATAmountJobCurrency: Decimal;
+    begin
+        // If the GenJnlLine currency is the same as the Job currency, return the Non-Deductible VAT Amount as-is
+        if GenJnlLine."Currency Code" = GenJnlLine."Job Currency Code" then
+            exit(GenJnlLine."Non-Deductible VAT Amount");
+
+        // If the Job has no currency (LCY), use the LCY amount
+        if GenJnlLine."Job Currency Code" = '' then
+            exit(GenJnlLine."Non-Deductible VAT Amount LCY");
+
+        // Convert the Non-Deductible VAT Amount from source currency to Job currency
+        // First, if the source currency is not LCY, convert to LCY
