+                GenJnlLine."Currency Factor",
+                GenJnlLine."Posting Date")
+        else
+            NonDeductibleVATAmountLCY := GenJnlLine."Non-Deductible VAT Amount LCY";
+
+        // Then convert from LCY to Job currency
+        NonDeductibleVATAmountJobCurrency := ConvertAmountFromLCY(
+            NonDeductibleVATAmountLCY,
+            GenJnlLine."Job Currency Code",
+            GenJnlLine."Job Currency Factor",
+            GenJnlLine."Posting Date");
+
+        exit(NonDeductibleVATAmountJobCurrency);
+    end;
+
+    local procedure ConvertAmountToLCY(Amount: Decimal; CurrencyCode: Code[10]; CurrencyFactor: Decimal; PostingDate: Date): Decimal
+    begin
+        if CurrencyCode = '' then
+            exit(Amount);
+
+        if CurrencyFactor = 0 then
+            exit(0);
+
+        exit(Round(Amount / CurrencyFactor));
+    end;
+
+    local procedure ConvertAmountFromLCY(Amount: Decimal; CurrencyCode: Code[10]; CurrencyFactor: Decimal; PostingDate: Date): Decimal
+    begin
+        if CurrencyCode = '' then
+            exit(Amount);
+
+        if CurrencyFactor = 0 then
+            exit(0);
+
