+
+    local procedure CorrectionForRoundingErrors(TrackingSpec: Record "Tracking Specification")
+    var
+        ReservEntry: Record "Reservation Entry";
+        ReservEntry2: Record "Reservation Entry";
+        TotalQtyBase: Decimal;
+        RoundingDiff: Decimal;
+    begin
+        // Correct for cumulative rounding errors when tracking lines are split
+        // This ensures the sum of split quantities equals the original quantity
+        
+        ReservEntry.SetTrackingFilterFromSpec(TrackingSpec);
+        ReservEntry.SetSourceFilter(TrackingSpec."Source Type", TrackingSpec."Source Subtype", 
+                                    TrackingSpec."Source ID", TrackingSpec."Source Ref. No.", false);
+        ReservEntry.SetSourceFilter(TrackingSpec."Source Batch Name", TrackingSpec."Source Prod. Order Line");
+        
+        if ReservEntry.FindSet() then begin
+            TotalQtyBase := 0;
+            repeat
+                TotalQtyBase += ReservEntry."Quantity (Base)";
+            until ReservEntry.Next() = 0;
+            
+            RoundingDiff := TrackingSpec."Quantity (Base)" - TotalQtyBase;
+            
+            if (RoundingDiff <> 0) and (Abs(RoundingDiff) <= 0.00001) then begin
+                // Apply rounding correction to the last entry
+                if ReservEntry.FindLast() then begin
+                    ReservEntry2 := ReservEntry;
+                    ReservEntry2."Quantity (Base)" += RoundingDiff;
+                    ReservEntry2.Modify(false);
+                end;
+            end;
+        end;
+    end;
+}
